const LOGO_PLACEMENTS = [
  { type: "white" as const, top: "5%", left: "4%", w: 140, delay: "0s", dur: 9, parallax: 0.22 },
  { type: "gradient" as const, top: "15%", right: "8%", w: 90, delay: "3s", dur: 8, parallax: -0.12 },
  { type: "white" as const, top: "45%", left: "-2%", w: 55, delay: "1s", dur: 10, parallax: 0.18 },
  { type: "gradient" as const, top: "55%", right: "12%", w: 120, delay: "5s", dur: 11, parallax: -0.08 },
  { type: "white" as const, top: "78%", left: "15%", w: 70, delay: "2s", dur: 7, parallax: 0.25 },
  { type: "gradient" as const, bottom: "12%", right: "20%", w: 100, delay: "4s", dur: 9, parallax: -0.15 },
  { type: "white" as const, top: "32%", right: "5%", w: 45, delay: "6s", dur: 10, parallax: 0.1 },
  { type: "gradient" as const, bottom: "25%", left: "10%", w: 80, delay: "1s", dur: 8, parallax: -0.2 },
];

export default function BlockchainDecorativeLogos() {
  const [scrollY, setScrollY] = useState(0);

  useEffect(() => {
    const onScroll = () => setScrollY(window.scrollY);
    onScroll();
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  return (
    <div className="pointer-events-none fixed inset-0 overflow-hidden z-0" aria-hidden>
      {LOGO_PLACEMENTS.map((p, i) => {
        const parallaxOffset = scrollY * p.parallax * 0.4;
        return (
          <div
            key={i}
            className={`absolute opacity-[0.15] will-change-transform transition-transform duration-[2472ms] ease-out ${p.type === "white" ? "backdrop-blur-md" : ""}`}
            style={{
              ...(p.top && { top: p.top }),
              ...(p.bottom && { bottom: p.bottom }),
              ...(p.left && { left: p.left }),
              ...(p.right && { right: p.right }),
              width: p.w,
              transform: `translateY(${parallaxOffset}px)`,
              animation: `tribe-logo-fade ${p.dur}s ease-in-out infinite`,
              animationDelay: p.delay,
            } as React.CSSProperties}
          >
            {p.type === "gradient" ? (
              <TribeLogoGradient gradientId={`tribe-deco-grad-${i}`} />
            ) : (
              <TribeLogoWhite />
            )}
          </div>
        );
      })}
    </div>
  );
}
